const staticData = $getWorkflowStaticData('global');
const lastProcessed = staticData.lastSalaryDate || '';
const txs = $input.first().json;
const arr = Array.isArray(txs) ? txs : (txs.transactions || []);

const salary = arr.find(t => {
  const name = (t.applicant_name || '').toLowerCase();
  const amt = parseFloat(t.amount || 0);
  return name.includes('mandala') && amt > 1000 && t.date !== lastProcessed;
});

if (!salary) return [{ json: { newSalary: false } }];

staticData.lastSalaryDate = salary.date;

return [{ json: {
  newSalary: true,
  salaryAmount: parseFloat(salary.amount),
  salaryDate: salary.date
} }];

const salaryData = $('Neues Gehalt prüfen').first().json;
const txs = $('Transaktionen 45 Tage').first().json;
const arr = Array.isArray(txs) ? txs : (txs.transactions || []);
const salary = salaryData.salaryAmount;

// Girokonto-Stand (IBAN endet auf 7000)
const balArr = $input.first().json;
const accounts = Array.isArray(balArr) ? balArr : [balArr];
const girokonto = accounts.find(a => (a.iban || '').endsWith('7000')) || accounts[0];
const currentBalance = parseFloat(girokonto.balance || 0);

const FIXKOSTEN = [
  { name: 'Miete',                  keywords: ['gronwald', 'sigrid'], amount: 470.00 },
  { name: 'Allianz Lebensversicherung', keywords: ['allianz lebens'],  amount: 130.00 },
  { name: 'Canada Life',            keywords: ['canada life'],         amount: 55.94  },
  { name: 'Telefonica',             keywords: ['telefonica'],          amount: 43.23  },
  { name: 'Vattenfall (Strom)',      keywords: ['vattenfall'],          amount: 33.00  },
  { name: 'Debeka KV',              keywords: ['debeka kran'],         amount: 28.29  },
  { name: 'ARAG',                   keywords: ['arag'],                amount: 18.30  },
  { name: 'Barmenia',               keywords: ['barmenia'],            amount: 4.61   },
];

// Fixkosten die DIESEN MONAT bereits abgebucht wurden
const now = new Date();
const cm = now.getMonth();
const cy = now.getFullYear();
const paidThisMonth = arr.filter(t => {
  const d = new Date(t.date);
  return parseFloat(t.amount) < 0 && d.getMonth() === cm && d.getFullYear() === cy;
});

const result = FIXKOSTEN.map(fk => {
  const paid = paidThisMonth.find(t =>
    fk.keywords.some(kw => (t.applicant_name || '').toLowerCase().includes(kw))
  );
  return { ...fk, paid: !!paid, paidAmount: paid ? Math.abs(parseFloat(paid.amount)) : null };
});

const stillOpen = result.filter(f => !f.paid).reduce((s, f) => s + f.amount, 0);
const transferAmount = currentBalance - stillOpen;
const fmt = n => n.toLocaleString('de-DE', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

let msg = `\u{1F4B0} *Gehaltseingang – ${fmt(salary)} €*\n`;
msg += `\u{1F4C5} ${new Date(salaryData.salaryDate).toLocaleDateString('de-DE')}\n`;
msg += `\u{1F3E6} Kontostand: *${fmt(currentBalance)} €*\n\n`;

const open = result.filter(f => !f.paid);
const paid_items = result.filter(f => f.paid);

if (open.length) {
  msg += `\u{1F4CB} *Noch offene Fixkosten:*\n`;
  open.forEach(f => { msg += `  • ${f.name}: ${fmt(f.amount)} €\n`; });
  msg += `  ∑ *${fmt(stillOpen)} €*\n\n`;
}
if (paid_items.length) {
  msg += `✅ *Bereits abgebucht:*\n`;
  paid_items.forEach(f => { msg += `  • ${f.name}: ${fmt(f.paidAmount || f.amount)} €\n`; });
  msg += `\n`;
}

msg += `\u{1F4B3} *→ ${fmt(transferAmount)} € auf C24 überweisen*`;

return [{ json: { message: msg, transferAmount, currentBalance, salary, stillOpen } }];

